def checkRecord(self, s: str) -> bool:
    count_absence = count_late = count_present = 0
    for c in s:
        if c == 'A':
            count_absence += 1
        elif c == 'L':
            count_late += 1
            if count_late >= 3:
                count_late = 0
        else:
            count_present += 1
    return count_absence <= 2 and count_late == 0

